const { MetricsRegistry, cluster } = require('zero-http');
const registry = new MetricsRegistry();

cluster((mgr) => {
    const app = createApp();
    app.use(metricsMiddleware({ registry }));
    mgr.enableMetrics(registry, { interval: 3000 });
    app.listen(3000);
});

